-- Create immutable transaction log table with cryptographic verification
CREATE TABLE transaction_log (
    tx_id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    tx_sequence BIGSERIAL UNIQUE NOT NULL,
    transaction_type VARCHAR(50) NOT NULL,
    amount DECIMAL(19, 4) NOT NULL,
    currency CHAR(3) NOT NULL,
    from_account VARCHAR(100) NOT NULL,
    to_account VARCHAR(100) NOT NULL,
    initiated_by VARCHAR(255) NOT NULL,
    client_ip INET NOT NULL,
    user_agent TEXT,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP NOT NULL,
    -- Cryptographic fields for non-repudiation
    tx_hash VARCHAR(64) NOT NULL, -- SHA-256 hash of transaction data
    previous_tx_hash VARCHAR(64), -- Hash of previous transaction (blockchain-style)
    digital_signature TEXT NOT NULL, -- RSA/ECDSA signature of transaction
    signing_key_id VARCHAR(100) NOT NULL,
    merkle_root VARCHAR(64), -- Merkle tree root for batch verification
    -- Metadata for audit
    metadata JSONB,
    CONSTRAINT valid_amount CHECK (amount >= 0)
);

-- Create immutable table to prevent UPDATE/DELETE
ALTER TABLE transaction_log SET (autovacuum_enabled = false);
CREATE POLICY transaction_append_only ON transaction_log
    FOR ALL
    USING (false)
    WITH CHECK (true);

-- Enable row-level security
ALTER TABLE transaction_log ENABLE ROW LEVEL SECURITY;

-- Create trigger to generate transaction hash before insert
CREATE OR REPLACE FUNCTION generate_transaction_hash()
RETURNS TRIGGER AS $$
DECLARE
    tx_data TEXT;
    prev_hash TEXT;
BEGIN
    -- Get previous transaction hash for chaining
    SELECT tx_hash INTO prev_hash
    FROM transaction_log
    ORDER BY tx_sequence DESC
    LIMIT 1;

    -- Concatenate transaction fields
    tx_data := NEW.tx_sequence || '|' ||
               NEW.transaction_type || '|' ||
               NEW.amount::TEXT || '|' ||
               NEW.currency || '|' ||
               NEW.from_account || '|' ||
               NEW.to_account || '|' ||
               NEW.initiated_by || '|' ||
               NEW.created_at::TEXT || '|' ||
               COALESCE(prev_hash, '0');

    -- Generate SHA-256 hash
    NEW.tx_hash := encode(digest(tx_data, 'sha256'), 'hex');
    NEW.previous_tx_hash := prev_hash;

    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_generate_tx_hash
    BEFORE INSERT ON transaction_log
    FOR EACH ROW
    EXECUTE FUNCTION generate_transaction_hash();

-- Prevent any modifications to existing records
CREATE OR REPLACE FUNCTION prevent_transaction_modification()
RETURNS TRIGGER AS $$
BEGIN
    RAISE EXCEPTION 'Transaction logs are immutable. Operation % not allowed.', TG_OP;
    RETURN NULL;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_prevent_update
    BEFORE UPDATE ON transaction_log
    FOR EACH ROW
    EXECUTE FUNCTION prevent_transaction_modification();

CREATE TRIGGER trg_prevent_delete
    BEFORE DELETE ON transaction_log
    FOR EACH ROW
    EXECUTE FUNCTION prevent_transaction_modification();

-- Create verification function to detect tampering
CREATE OR REPLACE FUNCTION verify_transaction_chain(
    start_sequence BIGINT DEFAULT 1,
    end_sequence BIGINT DEFAULT NULL
)
RETURNS TABLE(
    is_valid BOOLEAN,
    invalid_tx_id UUID,
    expected_hash TEXT,
    actual_hash TEXT,
    error_message TEXT
) AS $$
DECLARE
    rec RECORD;
    calculated_hash TEXT;
    tx_data TEXT;
BEGIN
    FOR rec IN
        SELECT *
        FROM transaction_log
        WHERE tx_sequence >= start_sequence
            AND (end_sequence IS NULL OR tx_sequence <= end_sequence)
        ORDER BY tx_sequence
    LOOP
        -- Recalculate hash
        tx_data := rec.tx_sequence || '|' ||
                   rec.transaction_type || '|' ||
                   rec.amount::TEXT || '|' ||
                   rec.currency || '|' ||
                   rec.from_account || '|' ||
                   rec.to_account || '|' ||
                   rec.initiated_by || '|' ||
                   rec.created_at::TEXT || '|' ||
                   COALESCE(rec.previous_tx_hash, '0');

        calculated_hash := encode(digest(tx_data, 'sha256'), 'hex');

        -- Verify hash matches
        IF calculated_hash != rec.tx_hash THEN
            is_valid := false;
            invalid_tx_id := rec.tx_id;
            expected_hash := calculated_hash;
            actual_hash := rec.tx_hash;
            error_message := 'Transaction hash mismatch - possible tampering detected';
            RETURN NEXT;
            RETURN;
        END IF;
    END LOOP;

    is_valid := true;
    error_message := 'Transaction chain verified successfully';
    RETURN NEXT;
END;
$$ LANGUAGE plpgsql;

