const { QldbDriver, RetryConfig } = require('amazon-qldb-driver-nodejs');
const { createHash } = require('crypto');

// Initialize QLDB driver
const qldbDriver = new QldbDriver(
  'financial-ledger', // Ledger name
  {
    region: 'us-east-1',
    retryConfig: new RetryConfig(3)
  }
);

/**
 * Record immutable financial transaction in QLDB
 * @returns {Object} Transaction record with cryptographic proof
 */
async function recordTransaction(transactionData) {
  const {
    transactionType,
    amount,
    currency,
    fromAccount,
    toAccount,
    initiatedBy,
    clientIp,
    metadata = {}
  } = transactionData;

  // Generate transaction signature
  const txData = JSON.stringify({
    transactionType,
    amount,
    currency,
    fromAccount,
    toAccount,
    initiatedBy,
    timestamp: new Date().toISOString()
  });

  const txSignature = createHash('sha256').update(txData).digest('hex');

  try {
    const result = await qldbDriver.executeLambda(async (txn) => {
      // Insert transaction into ledger
      const insertQuery = `
        INSERT INTO Transactions <<
          {
            'transactionId': '${generateTxId()}',
            'transactionType': '${transactionType}',
            'amount': ${amount},
            'currency': '${currency}',
            'fromAccount': '${fromAccount}',
            'toAccount': '${toAccount}',
            'initiatedBy': '${initiatedBy}',
            'clientIp': '${clientIp}',
            'txSignature': '${txSignature}',
            'timestamp': \`${new Date().toISOString()}\`,
            'metadata': ${JSON.stringify(metadata)}
          }
        >>`;

      const insertResult = await txn.execute(insertQuery);

      // Get document ID (unique identifier in QLDB)
      const documentId = insertResult.getResultList()[0].get('documentId').stringValue();

      // Query the committed transaction with block address
      const verifyQuery = `
        SELECT * FROM _ql_committed_Transactions
        WHERE metadata.id = '${documentId}'
      `;

      const verifyResult = await txn.execute(verifyQuery);
      const committedRecord = verifyResult.getResultList()[0];

      return {
        transactionId: documentId,
        blockAddress: committedRecord.get('blockAddress'),
        hash: committedRecord.get('hash'),
        timestamp: new Date().toISOString()
      };
    });

    console.log('Transaction recorded in immutable ledger:', result);
    return result;

  } catch (error) {
    console.error('Failed to record transaction:', error);
    throw new Error(`Transaction recording failed: ${error.message}`);
  }
}

/**
 * Verify transaction integrity using QLDB cryptographic proof
 * @param {string} transactionId - Document ID in QLDB
 * @returns {Object} Verification result with cryptographic proof
 */
async function verifyTransactionIntegrity(transactionId) {
  try {
    const result = await qldbDriver.executeLambda(async (txn) => {
      // Get transaction history (all revisions)
      const historyQuery = `
        SELECT * FROM history(Transactions)
        WHERE metadata.id = '${transactionId}'
      `;

      const historyResult = await txn.execute(historyQuery);
      const revisions = historyResult.getResultList();

      if (revisions.length === 0) {
        throw new Error('Transaction not found in ledger');
      }

      // Get cryptographic digest proof
      const proofQuery = `
        SELECT blockAddress, hash FROM _ql_committed_Transactions
        WHERE metadata.id = '${transactionId}'
      `;

      const proofResult = await txn.execute(proofQuery);
      const proof = proofResult.getResultList()[0];

      return {
        isValid: true,
        transactionId,
        revisionCount: revisions.length,
        blockAddress: proof.get('blockAddress'),
        cryptographicHash: proof.get('hash').stringValue(),
        verifiedAt: new Date().toISOString()
      };
    });

    return result;

  } catch (error) {
    console.error('Transaction verification failed:', error);
    return {
      isValid: false,
      error: error.message
    };
  }
}

/**
 * Get complete audit trail for an account
 * @param {string} accountId - Account identifier
 * @returns {Array} All transactions involving the account
 */
async function getAccountAuditTrail(accountId) {
  try {
    const result = await qldbDriver.executeLambda(async (txn) => {
      const query = `
        SELECT
          data.transactionId,
          data.transactionType,
          data.amount,
          data.currency,
          data.fromAccount,
          data.toAccount,
          data.timestamp,
          metadata.version,
          metadata.txTime
        FROM history(Transactions) AS h
        WHERE h.data.fromAccount = '${accountId}'
           OR h.data.toAccount = '${accountId}'
        ORDER BY h.metadata.txTime DESC
      `;

      const queryResult = await txn.execute(query);
      return queryResult.getResultList();
    });

    return result.map(record => ({
      transactionId: record.get('transactionId').stringValue(),
      type: record.get('transactionType').stringValue(),
      amount: record.get('amount').numberValue(),
      currency: record.get('currency').stringValue(),
      from: record.get('fromAccount').stringValue(),
      to: record.get('toAccount').stringValue(),
      timestamp: record.get('timestamp').stringValue(),
      ledgerVersion: record.get('version').numberValue(),
      committedAt: record.get('txTime').timestampValue()
    }));

  } catch (error) {
    console.error('Failed to retrieve audit trail:', error);
    throw error;
  }
}

/**
 * Generate unique transaction ID
 */
function generateTxId() {
  const timestamp = Date.now();
  const random = Math.random().toString(36).substring(2, 15);
  return `tx_${timestamp}_${random}`;
}

// Example usage
async function main() {
  // Record a transaction
  const txResult = await recordTransaction({
    transactionType: 'wire_transfer',
    amount: 50000.00,
    currency: 'USD',
    fromAccount: 'acct_12345',
    toAccount: 'acct_67890',
    initiatedBy: 'user@example.com',
    clientIp: '192.168.1.100',
    metadata: {
      purpose: 'Invoice payment INV-2024-001',
      approvedBy: 'manager@example.com'
    }
  });

  console.log('Transaction recorded:', txResult);

  // Verify transaction integrity
  const verification = await verifyTransactionIntegrity(txResult.transactionId);
  console.log('Transaction verification:', verification);

  // Get audit trail
  const auditTrail = await getAccountAuditTrail('acct_12345');
  console.log('Account audit trail:', auditTrail);
}

// Export functions
module.exports = {
  recordTransaction,
  verifyTransactionIntegrity,
  getAccountAuditTrail
};

const { MongoClient } = require('mongodb');
const { createHmac } = require('crypto');

// MongoDB connection
const uri = process.env.MONGODB_URI || 'mongodb://localhost:27017';
const client = new MongoClient(uri);

const SECRET_KEY = process.env.TRANSACTION_SIGNING_KEY; // Store in Key Vault

/**
 * Initialize transaction audit system with change streams
 */
async function initializeAuditSystem() {
  await client.connect();

  const db = client.db('financial_system');
  const transactionsCollection = db.collection('transactions');
  const auditLogCollection = db.collection('transaction_audit_log');

  // Create indexes for performance
  await transactionsCollection.createIndex({ transactionId: 1 }, { unique: true });
  await transactionsCollection.createIndex({ fromAccount: 1, timestamp: -1 });
  await auditLogCollection.createIndex({ transactionId: 1, auditSequence: 1 });
  await auditLogCollection.createIndex({ timestamp: -1 });

  // Set up Change Stream to monitor all transaction operations
  const changeStream = transactionsCollection.watch([
    {
      $match: {
        operationType: { $in: ['insert', 'update', 'replace', 'delete'] }
      }
    }
  ], {
    fullDocument: 'updateLookup',
    fullDocumentBeforeChange: 'whenAvailable'
  });

  console.log('Transaction audit system initialized. Monitoring all changes...');

  // Process change events in real-time
  changeStream.on('change', async (change) => {
    try {
      await captureAuditEvent(change, auditLogCollection);
    } catch (error) {
      console.error('Failed to capture audit event:', error);
      // Send alert - audit capture failure is critical
      await sendCriticalAlert({
        type: 'AUDIT_CAPTURE_FAILURE',
        error: error.message,
        change: change
      });
    }
  });

  changeStream.on('error', (error) => {
    console.error('Change stream error:', error);
    // Reconnect logic here
  });

  return { transactionsCollection, auditLogCollection, changeStream };
}

/**
 * Capture audit event with cryptographic signature
 */
async function captureAuditEvent(change, auditLogCollection) {
  const auditEntry = {
    auditId: generateAuditId(),
    transactionId: change.documentKey._id,
    operationType: change.operationType,
    timestamp: new Date(),
    clusterTime: change.clusterTime,

    // Before state (for updates/deletes)
    documentBeforeChange: change.fullDocumentBeforeChange || null,

    // After state (for inserts/updates)
    documentAfterChange: change.fullDocument || null,

    // Changed fields
    updatedFields: change.updateDescription?.updatedFields || null,
    removedFields: change.updateDescription?.removedFields || null,

    // Session info for accountability
    sessionId: change.lsid?.id || null,

    // Namespace
    database: change.ns.db,
    collection: change.ns.coll
  };

  // Generate cryptographic signature of audit entry
  const auditSignature = generateAuditSignature(auditEntry);
  auditEntry.signature = auditSignature;
  auditEntry.signatureAlgorithm = 'HMAC-SHA256';

  // Get sequence number for ordering
  const lastAudit = await auditLogCollection
    .findOne({}, { sort: { auditSequence: -1 } });

  auditEntry.auditSequence = (lastAudit?.auditSequence || 0) + 1;
  auditEntry.previousAuditSignature = lastAudit?.signature || null;

  // Store audit entry (this operation itself will trigger another change event,
  // but we filter it out by collection name)
  await auditLogCollection.insertOne(auditEntry);

  console.log(`Audit captured: ${auditEntry.operationType} on transaction ${auditEntry.transactionId}`);
}

/**
 * Create cryptographically signed transaction
 */
async function createSignedTransaction(transactionData, transactionsCollection) {
  const {
    transactionType,
    amount,
    currency,
    fromAccount,
    toAccount,
    initiatedBy,
    metadata = {}
  } = transactionData;

  const transaction = {
    transactionId: generateTransactionId(),
    transactionType,
    amount,
    currency,
    fromAccount,
    toAccount,
    initiatedBy,
    status: 'completed',
    timestamp: new Date(),
    metadata,

    // Version tracking
    version: 1,
    createdAt: new Date(),
    updatedAt: new Date()
  };

  // Generate transaction signature
  transaction.signature = generateTransactionSignature(transaction);
  transaction.signatureAlgorithm = 'HMAC-SHA256';

  try {
    const result = await transactionsCollection.insertOne(transaction);

    return {
      success: true,
      transactionId: transaction.transactionId,
      insertedId: result.insertedId,
      signature: transaction.signature
    };
  } catch (error) {
    console.error('Transaction creation failed:', error);
    throw new Error(`Failed to create transaction: ${error.message}`);
  }
}

/**
 * Verify transaction has not been tampered with
 */
async function verifyTransactionIntegrity(transactionId, transactionsCollection) {
  const transaction = await transactionsCollection.findOne({ transactionId });

  if (!transaction) {
    return { isValid: false, error: 'Transaction not found' };
  }

  const storedSignature = transaction.signature;
  const tempTransaction = { ...transaction };
  delete tempTransaction.signature;
  delete tempTransaction.signatureAlgorithm;

  const calculatedSignature = generateTransactionSignature(tempTransaction);

  const isValid = storedSignature === calculatedSignature;

  return {
    isValid,
    transactionId,
    storedSignature,
    calculatedSignature,
    message: isValid 
      ? 'Transaction integrity verified' 
      : 'TAMPERING DETECTED - Signature mismatch'
  };
}

/**
 * Get complete audit trail for a transaction
 */
async function getTransactionAuditTrail(transactionId, auditLogCollection) {
  const auditEvents = await auditLogCollection
    .find({ transactionId })
    .sort({ auditSequence: 1 })
    .toArray();

  // Verify audit chain integrity
  let chainValid = true;
  for (let i = 0; i < auditEvents.length; i++) {
    const event = auditEvents[i];
    const tempEvent = { ...event };
    delete tempEvent._id;
    delete tempEvent.signature;
    delete tempEvent.signatureAlgorithm;

    const calculatedSig = generateAuditSignature(tempEvent);

    if (calculatedSig !== event.signature) {
      chainValid = false;
      event.tampered = true;
    }
  }

  return {
    transactionId,
    eventCount: auditEvents.length,
    chainValid,
    events: auditEvents.map(e => ({
      auditId: e.auditId,
      sequence: e.auditSequence,
      operation: e.operationType,
      timestamp: e.timestamp,
      tampered: e.tampered || false
    }))
  };
}

/**
 * Generate HMAC-SHA256 signature for transaction
 */
function generateTransactionSignature(transaction) {
  const data = JSON.stringify(transaction, Object.keys(transaction).sort());
  return createHmac('sha256', SECRET_KEY).update(data).digest('hex');
}

/**
 * Generate HMAC-SHA256 signature for audit entry
 */
function generateAuditSignature(auditEntry) {
  const data = JSON.stringify(auditEntry, Object.keys(auditEntry).sort());
  return createHmac('sha256', SECRET_KEY).update(data).digest('hex');
}

function generateTransactionId() {
  return `tx_${Date.now()}_${Math.random().toString(36).substring(2, 11)}`;
}

function generateAuditId() {
  return `audit_${Date.now()}_${Math.random().toString(36).substring(2, 11)}`;
}

async function sendCriticalAlert(alertData) {
  // Implement alerting (PagerDuty, Slack, etc.)
  console.error('CRITICAL ALERT:', alertData);
}

// Example usage
async function main() {
  const { transactionsCollection, auditLogCollection } = await initializeAuditSystem();

  // Create signed transaction
  const result = await createSignedTransaction({
    transactionType: 'wire_transfer',
    amount: 50000.00,
    currency: 'USD',
    fromAccount: 'acct_12345',
    toAccount: 'acct_67890',
    initiatedBy: 'user@example.com',
    metadata: { reference: 'INV-2024-001' }
  }, transactionsCollection);

  console.log('Transaction created:', result);

  // Verify integrity
  const verification = await verifyTransactionIntegrity(
    result.transactionId, 
    transactionsCollection
  );
  console.log('Verification:', verification);

  // Get audit trail
  setTimeout(async () => {
    const auditTrail = await getTransactionAuditTrail(
      result.transactionId, 
      auditLogCollection
    );
    console.log('Audit trail:', auditTrail);
  }, 2000);
}

module.exports = {
  initializeAuditSystem,
  createSignedTransaction,
  verifyTransactionIntegrity,
  getTransactionAuditTrail
};
